module.exports=[20715,a=>{a.v(JSON.parse('{"Index":{"title":"ElektroNova - Fuqizojmë Sigurinë Tuaj","description":"Zgjidhje premium për sigurinë dhe instalimet elektrike në tërë Kosovën.","hero_badge":"ElektroNova - Fuqizojmë Sigurinë Tuaj","hero_h1":"Fuqizojmë <gradient>Sigurinë</gradient> Tuaj me Teknologji","hero_p":"ElektroNova ofron zgjidhje premium për monitorim, alarm dhe instalime elektrike. Siguria juaj është prioriteti ynë kryesor në mbarë Kosovën.","services_title":"Shërbimet tona <highlight>Kryesore</highlight>","services_highlight":"Kryesore","services_p":"Ne ofrojmë një gamë të gjerë shërbimesh teknologjike për të siguruar mjedisin tuaj.","view_all_services":"Shih të gjitha shërbimet","testimonials_title":"Besimi i <highlight>Klientëve</highlight>","testimonials_p":"Çfarë thonë ata që kanë besuar sigurinë e tyre në duart tona.","mission_badge":"Misioni & Historia Jonë","mission_title":"Mbi Një Dekadë Përvojë në <highlight>Teknologjinë e Sigurisë</highlight>","mission_p1":"ElektroNova nuk është thjesht një emër në industrinë e sigurisë; është një premtim për mbrojtje dhe profesionalizëm. E themeluar në Pejë, kompania jonë lindi nga nevoja për të sjellë standarde evropiane në fushën e video-vëzhgimit dhe instalimeve elektrike në tërë Kosovën.","mission_p2":"Gjatë viteve, ne kemi evoluar së bashku me teknologjinë. Nga kamerat analoge të para 10 viteve, sot jemi lider në instalimin e sistemeve me Inteligjencë Artificiale, njohje të fytyrave dhe sistemeve smart home që menaxhohen plotësisht nga celulari.","mission_p3":"Sot, ne mbulojmë çdo qytet të Kosovës, duke ofruar shërbime të shpejta dhe mirëmbajtje 24/7. Ne besojmë se teknologjia duhet t\'i shërbejë njerëzve, andaj çdo projekt i yni projektohet në mënyrë specifike për të plotësuar nevojat unike të klientëve tanë.","recent_work_title":"Punët tona të <highlight>Fundit</highlight>","recent_work_p":"Pamje direkte nga instalimet tona reale në tërë Kosovën.","view_full_gallery":"Shih Galerinë e Plotë","why_title":"Pse të zgjidhni <highlight>ElektroNova</highlight>?","why_1_title":"Instalim Profesional & Kabllim i Fshehur","why_1_p":"Teknikët tanë të trajnuar sigurojnë që çdo instalim të kryhet sipas standardeve më të larta të sigurisë, duke fshehur dhe mbrojtur çdo kabull.","why_2_title":"Mbështetje Lokale 24/7 në tërë Kosovën","why_2_p":"Me seli në Pejë, ne mbulojmë të gjitha qytetet e Kosovës me ndërhyrje të shpejtë, mirëmbajtje dhe asistencë teknike.","why_3_title":"Teknologjia e Fundit e Brendeve Botërore","why_3_p":"Punojmë vetëm me brendet lider botërorë si Dahua, Hikvision dhe Ajax për të garantuar jetëgjatësi.","consultation_title":"Kërkoni një Konsultë <highlight>Falas</highlight>","faq_title":"Pyetjet e <highlight>Shpeshta</highlight>","faq_p":"Çfarë dëshirojnë të dinë klientët tanë para se të instalojnë sistemet e sigurisë.","faq_1_q":"A mund t\'i shoh kamerat nga telefoni kudo që jam?","faq_1_a":"Po, plotësisht. Sistemet tona lidhen me internetin dhe ju lejojnë të shihni pamjet në kohë reale falas përmes aplikacioneve zyrtare Android dhe iOS.","faq_2_q":"Sa kohë zgjat një instalim i plotë?","faq_2_a":"Për një shtëpi mesatare me 4 deri 8 kamera, instalimi zakonisht përfundohet brenda një dite pune, duke përfshirë kabllimin dhe konfigurimin e aplikacionit.","faq_3_q":"Çfarë ndodh nëse bie rryma apo interneti?","faq_3_a":"Sistemet tona mund të pajisen me bateri rezervë (UPS) që mbajnë kamerat ndezur. Nëse bie interneti, regjistrimi vazhdon në Hard Disk lokalisht.","faq_4_q":"A ofroni garanci për pajisjet dhe punën?","faq_4_a":"Po, ElektroNova ofron garanci të plotë për të gjitha pajisjet e brendeve zyrtare (1-2 vite) si dhe garanci për korrektësinë e instalimit teknik.","faq_5_q":"A është sistemi i alarmit i vështirë për t\'u përdorur?","faq_5_a":"Jo, sistemet tona moderne bëhen me kod ose pult, dhe njoftimet vijnë në celular në gjuhën shqipe, duke e bërë shumë të thjeshtë për secilin.","faq_6_q":"A mbuloni të gjithë territorin e Kosovës?","faq_6_a":"Po, ekipi ynë mobil vjen në çdo qytet dhe fshat të Kosovës për llogaritje të ofertës, instalim dhe mirëmbajtje të sistemeve.","brands_p":"Punojmë me brendet më të mira botërore"},"Navigation":{"home":"Ballina","about":"Rreth Nesh","services":"Shërbimet","portfolio":"Portofolio","brands":"Brendet","blog":"Blogu","faq":"FAQ","contact":"Kontakti","footer_desc":"Zgjidhje premium për sigurinë dhe instalimet elektrike. Fuqizojmë sigurinë tuaj me teknologjinë më të fundit.","quick_links":"Lidhje të Shpejta","contact_us":"Na Kontaktoni","working_hours":"Orari i Punës","mon_fri":"E hënë - E premte","sat_sun":"E shtunë - E diel","closed":"Mbyllur","rights":"Të gjitha të drejtat e rezervuara.","privacy_policy":"Politika e Privatësisë","terms_of_service":"Kushtet e Përdorimit","locations":"Lokacionet"},"Common":{"whatsapp":"Na kontaktoni në WhatsApp","call":"Thirrni tani","quote":"Kërkoni ofertë","send":"Dërgo","name":"Emri Mbiemri","email":"Email Adresa","phone":"Numri i Telefonit","message":"Mesazhi juaj","sending":"Duke u dërguar...","success_title":"Ju faleminderit!","success_message":"Mesazhi juaj u dërgua me sukses. Ekipi ynë do t\'ju kontaktojë së shpejti.","error_message":"Diçka shkoi keq. Ju lutem provoni përsëri ose na kontaktoni në WhatsApp.","send_another":"Dërgoni një mesazh tjetër"},"Blog":{"title":"Blogu i <highlight>ElektroNova</highlight>","subtitle":"Këshilla profesionale, krahasime produktesh dhe lajmet e fundit nga bota e sigurisë teknologjike.","meta_description":"Lexoni artikujt tanë të fundit rreth sigurisë, teknologjisë CCTV dhe instalimeve elektrike falas.","back_to_blog":"Kthehu te të gjithë artikujt","security_expert":"Ekspert i Sigurisë","questions_title":"Keni pyetje rreth kësaj teme?","share":"Shpërndaje","related_services":"Shërbime të Ndërlidhura"},"Services":{"title_main":"Shërbimet tona","title_highlight":"Profesionale","title_suffix":"","description":"ElektroNova ofron zgjidhje të kompletuara për sigurinë dhe nevojat elektrike. Nga projektimi deri te instalimi dhe mirëmbajtja.","cat_cctv":"Sisteme të Monitorimit (CCTV)","cat_security":"Alarme dhe Siguri","cat_electrical":"Instalime Elektrike & Rrjeta","service_description":"Zgjidhje profesionale e përshtatur për nevojat tuaja specifike, duke garantuar cilësi dhe siguri maksimale.","cta_title":"Nuk jeni të sigurt çfarë ju duhet?","cta_desc":"Na kontaktoni sot për një konsultë falas dhe vlerësim të mjedisit tuaj nga ekspertët tanë.","call_expert":"Thirrni Ekspertin","whatsapp":"WhatsApp","related_articles":"Artikuj të Ndërlidhur","back_to_services":"Kthehu te të gjitha shërbimet","service_description_title":"Përshkrimi i Shërbimit","main_benefits":"Përfitimet Kryesore","tech_used":"Teknologjia e Përdorur","where_applies":"Ku mund të aplikohet?","install_process":"Procesi i Instalimit","service_faq":"Pyetjet rreth Shërbimit","get_quote":"Merrni një Ofertë","quote_desc":"Interesoheni për këtë shërbim? Plotësoni formën më poshtë dhe ekipi ynë do t\'ju kontaktojë brenda 24 orëve.","need_help":"Nevojë për Ndihmë?","free_cons_desc":"Na thirrni në çdo kohë për konsultim falas."},"Portfolio":{"title_main":"Portofolio i","title_highlight":"Realizimeve","description":"Pamje nga instalimet tona reale në terren. Çdo foto tregon përkushtimin tonë ndaj cilësisë dhe profesionalizmit.","cta_title":"Gati për të siguruar pronën tuaj?","cta_desc":"Ne vijmë kudo në Kosovë për vlerësimin e projektit tuaj pa asnjë pagesë.","request_quote":"Kërko Ofertën","call_phone":"Thirr në Telefon"},"About":{"title_main":"Rreth","title_highlight":"ElektroNova","vision_title":"Vizioni ynë","vision_p":"Themeluar më 08 Janar 2025 në qytetin e Pejës, ElektroNova lindi me një mision të qartë: të bëhet lider në ofrimin e zgjidhjeve të sigurisë dhe instalimeve elektrike në tërë territorin e Kosovës. Vizioni ynë është të fuqizojmë sigurinë tuaj përmes teknologjisë më të avancuar, duke krijuar mjedise më të sigurta për familjet dhe bizneset. Ne besojmë se çdo shtëpi meriton mbrojtje maksimale dhe çdo biznes meriton stabilitet operativ.","integrity_title":"Integriteti","integrity_p":"Ne veprojmë me ndershmëri absolute në çdo konsultim. Nëse një sistem nuk ju nevojitet, ne nuk do t\'ju rekomandojmë atë. Transparenca është shtylla jonë kryesore.","innovation_title":"Inovacioni","innovation_p":"Bota e sigurisë ndryshon çdo ditë. Ekipi ynë monitoron trendet globale për të sjellë teknologjitë më të fundit AI direkt në shtëpinë apo biznesin tuaj.","standards_title":"Standardet Profesionale","standards_p1":"Në ElektroNova, ne nuk bëjmë kompromis me cilësinë. Çdo projekt, qoftë një instalim i thjeshtë kamere apo një sistem kompleks elektrik industrial, trajtohet me profesionalizëm maksimal. Ne besojmë që siguria fillon nga detajet, andaj përdorim vetëm brendet më të besueshme botërore si Dahua, Hikvision dhe Ajax.","standards_p2":"Procesi ynë i punës është i certifikuar dhe ndjek udhëzimet më të rrepta teknike. Ne sigurohemi që çdo kabull të jetë i mbrojtur, çdo lidhje të jetë e izoluar dhe çdo pajisje të jetë e konfiguruar për performancë maksimale dhe rezistencë ndaj kushteve atmosferike.","quote_text":"\\"Siguria juaj nuk është thjesht punë për ne, është përgjegjësi. Ne kombinojmë pasionin për teknologjinë me përkushtimin ndaj klientit për të ofruar paqe dhe qetësi shpirtërore.\\"","geography_title":"Rrënjët në Pejë, Mbulim në Kosovë","geography_p1":"Megjithëse seli jonë kryesore ndodhet në Pejë (Haxhi Muzlija nr 48), ElektroNova operon me një rrjet mobil që mbulon çdo qoshe të Kosovës. Kemi arritur të ndërtojmë një reputacion të pathyeshëm nga Prishtina në Prizren, dhe nga Mitrovica në Gjilan.","geography_p2":"Lidhja jonë me komunitetin është e fortë. Ne kuptojmë nevojat specifike të banorëve të zonës së Rrafshit të Dukagjinit dhe më gjerë. Kjo na lejon të ofrojmë zgjidhje që janë jo vetëm teknike, por edhe praktike për jetën e përditshme të bashkëqytetarëve tanë.","stat_founded":"Themeluar","stat_coverage":"Qytete Mbulim","stat_support":"Asistencë","stat_reliability":"Besueshmëri"},"Contact":{"title_main":"Na","title_highlight":"Kontaktoni","description":"Keni një pyetje apo kërkoni një ofertë? Ekipi ynë është i gatshëm t\'ju ndihmojë për çdo nevojë të sigurisë dhe energjisë.","office_title":"Zyra jonë","google_maps":"Hape në Google Maps →","contact_details":"Detajet e Kontaktit","hours_title":"Orari i Punës","send_message":"Dërgoni një","message_highlight":"Mesazh","map_label":"Harta e Lokacionit — ElektroNova Pejë"},"FAQPage":{"title_main":"Pyetjet e","title_highlight":"Shpeshta","description":"Gjithçka që ju duhet të dini për shërbimet tona të sigurisë.","q1":"A mund të shoh pamjet e kamerave nga jashtë vendit?","a1":"Po, absolutisht. Të gjitha sistemet tona CCTV janë të lidhura me Cloud. Përmes aplikacionit në telefonin tuaj, ju mund të monitoroni pronën tuaj në kohë reale nga çdo vend i botës që ka qasje në internet. Ky shërbim është falas dhe i enkriptuar për sigurinë tuaj.","q2":"Sa kushton një sistem i plotë i kamerave për një shtëpi?","a2":"Çmimi varet nga numri i kamerave, rezolucioni (2MP, 4MP apo 4K) dhe sasia e memorisë për regjistrim. Ne ofrojmë konsulta falas ku vijmë në lokacionin tuaj dhe ju japim një ofertë të detajuar që i përshtatet buxhetit dhe nevojave tuaja specifike.","q3":"A duhet të shpohen muret për të instaluar alarmin?","a3":"Nëse zgjidhni sistemet tona Wireless (si brendi Ajax), nuk ka nevojë për asnjë shpim apo kabllim të dukshëm. Senzorët vendosen me mbajtëse magnetike ose vida minimale. Kjo i bën ato ideale për shtëpitë e sapo renovuara apo apartamentet.","q4":"Çka ndodh nëse bie rryma?","a4":"Sistemet tona janë të pajisura me bateri rezervë (UPS). Në rast të ndaljes së rrymës, alarmi dhe kamerat vazhdojnë të punojnë deri në 8-12 orë (varësisht nga konfigurimi). Ju do të njoftoheni në telefon menjëherë sapo sistemi të kalojë në bateri.","q5":"A ofroni mirëmbajtje pas instalimit?","a5":"Po, ElektroNova ofron kontrata të rregullta mirëmbajtjeje për bizneset dhe asistencë sipas kërkesës për klientët privatë. Ne kujdesemi që lentet e kamerave të jenë të pastra, Hard Disku të jetë në gjendje të mirë dhe sistemi i alarmit të testohet periodikisht.","q6":"A mbuloni qytetin tim me shërbime?","a6":"Ne mbulojmë tërë territorin e Kosovës. Megjithëse seli jonë është në Pejë, ekipet tona teknike lëvizin çdo ditë në Prishtinë, Prizren, Mitrovicë, Gjakovë, Gjilan, Ferizaj dhe në të gjitha komunat e tjera.","not_found_title":"Nuk e gjetët përgjigjen?","not_found_desc":"Ekipi ynë është i gatshëm t\'ju ndihmojë me çdo paqartësi tjetër.","contact_us":"Na Kontaktoni","whatsapp":"Na shkruani në WhatsApp"},"Locations":{"kosovo":"Kosovë","services_in":"Shërbimet tona në","realizations_in":"Realizimet tona në","why_elektronova_in":"Pse ElektroNova në","local_presence_desc":"Duke qenë prezent lokalisht, ne kuptojmë sfidat specifike të sigurisë që kanë qytetarët dhe bizneset në {city}. Ne ofrojmë një kombinim të teknologjisë globale dhe kujdesit lokal.","service_coverage":"Mbulimi i Shërbimit","coverage_desc":"ElektroNova mbulon çdo lagje dhe zonë rurale në {city}. Pavarësisht nëse jeni në qendër të qytetit apo në zonat periferike, ekipi ynë mobil vjen te ju për instalim dhe asistencë teknike.","consultation_in":"Konsultë në","consultation_desc":"Dëshironi të siguroni pronën tuaj në {city}? Plotësoni formën për një vlerësim falas në terren.","local_line":"Linja Lokale:","fast_service_kosovo":"Shërbim i shpejtë për tërë Kosovën"},"Cities":{"prishtine":"Prishtinë","prizren":"Prizren","peje":"Pejë","ferizaj":"Ferizaj","gjilan":"Gjilan","mitrovice":"Mitrovicë","gjakove":"Gjakovë","fushe-kosove":"Fushë Kosovë","podujeve":"Podujevë","vushtrri":"Vushtrri","suhareke":"Suharekë","rahovec":"Rahovec","lipjan":"Lipjan","kamenice":"Kamenicë","decan":"Deçan","istog":"Istog","malisheve":"Malishevë","skenderaj":"Skenderaj","gracanice":"Graçanicë","kline":"Klinë","shtime":"Shtime","obiliq":"Obiliq","drenas":"Drenas","junik":"Junik","hani-i-elezit":"Hani i Elezit"},"Compliance":{"privacy_title":"Politika e Privatësisë","cookie_title":"Politika e Kukive","terms_title":"Kushtet e Përdorimit","last_updated":"Përditësuar së fundmi: 17 Mars 2026","cookie_banner_title":"Ne vlerësojmë privatësinë tuaj","cookie_banner_desc":"Ne përdorim kuki për të përmirësuar përvojën tuaj të lundrimit, për të shfaqur reklama ose përmbajtje të personalizuara dhe për të analizuar trafikun tonë. Duke klikuar \\"Prano të Gjitha\\", ju jepni pëlqimin për përdorimin e kukive tona.","accept_all":"Prano të Gjitha","reject_all":"Refuzo të Gjitha","customize":"Personalizo","save_preferences":"Ruaj Preferencat","manage_cookies":"Menaxho Kukit","form_notice":"Duke dërguar këtë formë, ju pajtoheni me përpunimin e të dhënave tuaja nga ElektroNova me qëllim të përgjigjes ndaj kërkesës suaj. Për më shumë, shihni [privacy_policy].","form_checkbox":"Pajtohem me politikën e privatësisë","categories":{"necessary":"Të Domosdoshme","necessary_desc":"Këto kuki janë thelbësore për funksionimin e faqes dhe nuk mund të fiken.","analytics":"Analitike","analytics_desc":"Na ndihmojnë të kuptojmë se si vizitorët ndërveprojnë me faqen.","marketing":"Marketing","marketing_desc":"Përdoren për të gjurmuar vizitorët ndërmjet faqeve për reklamim të personalizuar."},"privacy_sections":{"s1_title":"1. Kontrolluesi i të Dhënave","s1_content":"ElektroNova, me seli në Rr. Haxhi Muzlija nr 48, 30000 Pejë, Kosovë, është kontrolluesi i të dhënave tuaja personale. Mund të na kontaktoni në endritsmajlib@gmail.com për çdo pyetje.","s2_title":"2. Të Dhënat që Mbledhim","s2_content":"Ne mbledhim të dhëna përmes: 1) Formave të kontaktit (Emri, Email, Telefon, Qyteti), 2) Analitikës (Adresa IP, lloji i shfletuesit), 3) Kukive (Identifikuesit e gjurmimit).","s3_title":"3. Baza Ligjore","s3_content":"Ne përpunojmë të dhënat tuaja bazuar në pëlqimin tuaj të shprehur (Neni 6 i Ligjit Nr. 06/L-082) dhe për nevojën e përmbushjes së një kontrate ose kërkesave parakontraktuale.","s4_title":"4. Qëllimi i Përpunimit","s4_content":"Të dhënat tuaja përdoren vetëm për t\'iu përgjigjur kërkesave tuaja për shërbim, për të përmirësuar performancën e faqes sonë dhe për të garantuar sigurinë e saj.","s5_title":"5. Periudha e Ruajtjes","s5_content":"Ne i mbajmë të dhënat tuaja personale vetëm për aq kohë sa është e nevojshme për qëllimet për të cilat janë mbledhur ose për të përmbushur kërkesat ligjore.","s6_title":"6. Të Drejtat tuaja","s6_content":"Sipas Ligjit të Kosovës Nr. 06/L-082, ju keni të drejtë të keni qasje, të korrigjoni ose të fshini të dhënat tuaja, dhe të drejtën për të kundërshtuar përpunimin. Kontaktoni zyrën tonë për këto të drejta.","s7_title":"7. Palët e Treta","s7_content":"Ne nuk i shesim të dhënat tuaja. Ne përdorim përpunues të besuar për analitikë (Google) dhe harta, të cilët janë në përputhje me standardet e mbrojtjes së të dhënave.","s8_title":"8. Siguria","s8_content":"Ne zbatojmë masa të larta teknike dhe organizative për të parandaluar qasjen e paautorizuar ose shkeljet e të dhënave."},"terms_sections":{"t1_title":"1. Pranimi i Kushteve","t1_content":"Duke hyrë dhe përdorur faqen e internetit të ElektroNova, ju pranoni të jeni të lidhur me këto Kushte të Përdorimit dhe të gjitha ligjet dhe rregulloret e zbatueshme në Kosovë.","t2_title":"2. Pronësia Intelektuale","t2_content":"Materialet në këtë faqe (tekstet, imazhet, logot) janë pronë intelektuale e ElektroNova. Ju nuk lejohet të kopjoni ose përdorni ato për qëllime komerciale pa pëlqimin tonë paraprak me shkrim.","t3_title":"3. Deklarata e Mospërgjegjësisë","t3_content":"ElektroNova bën çdo përpjekje për të siguruar saktësinë e informacionit, por nuk garanton që materialet janë gjithmonë të sakta, të plota ose aktuale.","t4_title":"4. Kontrata Formale","t4_content":"Përshkrimet e shërbimeve janë për qëllime informative. Një kontratë formale do të lidhet për çdo projekt apo instalim specifik."}}}'))}];

//# sourceMappingURL=Desktop_elektronova-recovered_messages_sq_json_cb90395d._.js.map